B.a_5=new A.aH(B.dm,["Clean underneath beverage lines and steel polish metal trim on Line 6.","Clean underneath beverage lines and steel polish metal trim on Line 1 and 2, including the nearest cereal station.","Clean underneath beverage lines and steel polish metal trim on Line 4, including the nearest cereal station."],t.li)
B.a_a=new A.aH(B.dm,["Sanitize and organize under shelves and the student table in Cafe West.","Deep clean the panini presses.","Swap out and clean breakfast topping holders and large white tubs."],t.li)
B.a_7=new A.aH(B.dm,["Clean all of the sneeze guards.","On serving lines, wipe underneath and scrub the white plastic boards.","Wash dustpans in the pan machine, replace sheet pans on the first three racks in Locker 10, and discard condiments 3 days or older."],t.li)
B.a_9=new A.aH(B.dm,["Deep clean the right-side condiment dispensers in Cafe West and the condiment dispensers by D-100.","Deep clean the left-side condiment dispensers and organize the station including underneath.","Polish the metal trim and sanitize and organize underneath shelves and cupboards on the island."],t.li)
B.a_c=new A.aH(B.dm,["Defrost and sanitize the Blue Bunny ice cream freezer.","Clean and organize under the fruit bar and wipe out the microwave.","Clean Cafe West warmers."],t.li)
B.a_4=new A.aH(B.dm,["Maintain the mop closet and mop the BIB room.","Wash red buckets in the pan machine at the end of shift and deep clean the dustpans with hose and Pantastic.","Maintain the Dish Return closet and Vacuum closet."],t.li)
B.a_b=new A.aH(B.dm,["Clean pillars in Cafe West and swap towel buckets under the student table and both serving lines.","Clean drip tubs under hanging rag bags in the custodial closet.","Spot mop and sweep the red floors."],t.li)
