B.a_N={Eggs:0}
B.Up=s(["Stage eggs, oil or butter, spatulas, and pans before the rush starts.","Preheat the flat top fully before cooking.","Cook in controlled batches and pull the eggs before they overcook.","Keep communicating with the runner and the cook when food is getting low."],t.s)
B.ZG=new A.aH(B.a_N,[B.Up],t.Q)
B.a_I={"French Toast Sticks":0}
B.Uz=s(["French toast sticks should be fried for 4 minutes.","Cook in controlled batches so they stay crisp and do not get soggy.","Tell the runner or cook early when you are getting low."],t.s)
B.ZV=new A.aH(B.a_I,[B.Uz],t.Q)
B.a_Z={"Fried Chicken":0}
B.VV=s(["Confirm fryer setup and safety checks with the cook before starting.","Do not overcrowd the fryer.","Let the cook set the timing and doneness standard for the batch.","Keep the hold pan stocked and the fryer area clean and organized."],t.s)
